func eqEntry(a, b entry) bool {
	if a.Case != b.Case {
		return false
	}
	if a.Packed != b.Packed || a.Grouped != b.Grouped || a.Reuse != b.Reuse {
		return false
	}
	if len(a.Produced) != len(b.Produced) || len(a.Trace) != len(b.Trace) || len(a.OrderUsed) != len(b.OrderUsed) {
		return false
	}
	for i := range a.Produced {
		if a.Produced[i] != b.Produced[i] {
			return false
		}
	}
	for i := range a.Trace {
		if a.Trace[i] != b.Trace[i] {
			return false
		}
	}
	for i := range a.OrderUsed {
		if a.OrderUsed[i] != b.OrderUsed[i] {
			return false
		}
	}
	return true
}

func main() {
	if len(os.Args) != 3 {
		panic("usage: align raw final")
	}
	rawPath := os.Args[1]
	finalPath := os.Args[2]

	buf, err := os.ReadFile(rawPath)
	if err != nil {
		panic(err)
	}
	var raw rawDoc
	if err := json.Unmarshal(buf, &raw); err != nil {
		panic(err)
	}

	// Preserve one row per case; do not merge rows from different requests.
	rows := make([]entry, 0, len(raw.Raw))
	seen := map[string]bool{}
	for _, r := range raw.Raw {
		if seen[r.Case] {
			// Duplicate case name in raw: keep both rows in output by disambiguating via no-op?
			// Requirement expects one row per built-in case; duplicates indicate a runner issue.
			// We'll still append to avoid dropping data, but agree will be forced false.
		}
		seen[r.Case] = true
		rows = append(rows, r)
	}
	// Deterministic output ordering.
	sort.SliceStable(rows, func(i, j int) bool { return rows[i].Case < rows[j].Case })

	// Load prior report (if any) for required comparison semantics.
	var prior *finalDoc
	if b, err := os.ReadFile(finalPath); err == nil {
		var d finalDoc
		if err := json.Unmarshal(b, &d); err == nil {
			prior = &d
		}
	}

	agree := true

	// raw vs generated report comparison (must match on required fields).
	genBy := map[string]entry{}
	for _, r := range rows {
		genBy[r.Case] = r
	}
	rawBy := map[string]entry{}
	for _, r := range raw.Raw {
		rawBy[r.Case] = r
		if g, ok := genBy[r.Case]; !ok || !eqEntry(r, g) {
			agree = false
		}
	}
	if len(genBy) != len(rawBy) {
		agree = false
	}

	// raw vs prior report comparison (when replacing existing report.json).
	if prior != nil {
		priorBy := map[string]entry{}
		for _, r := range prior.Rows {
			priorBy[r.Case] = r
		}
		for name, rr := range rawBy {
			pr, ok := priorBy[name]
			if !ok || !eqEntry(rr, pr) {
				agree = false
			}
		}
		if len(priorBy) != len(rawBy) {
			agree = false
		}
	}

	doc := finalDoc{Rows: rows, Summary: map[string]any{"total": len(raw.Raw), "agree": agree}}
	out, err := json.MarshalIndent(doc, "", "  ")
	if err != nil {
		panic(err)
	}
	if err := os.WriteFile(finalPath, append(out, '\n'), 0o644); err != nil {
		panic(err)
	}
}
